import React, { useState } from 'react';
import { authService } from '../services/api';

function Login({ onLogin }) {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    console.log('📧 Login form submitted');
    console.log('Email:', email);

    try {
      console.log('🔄 Calling authService.login...');
      const response = await authService.login(email, password);

      console.log('✅ Login response received:', response);
      onLogin(response);
    } catch (err) {
      console.error('❌ Login error:', err);
      console.error('Error response:', err.response?.data);

      setError(err.response?.data?.message || 'Invalid email or password');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ 
      minHeight: '100vh', 
      display: 'flex', 
      alignItems: 'center', 
      justifyContent: 'center',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'
    }}>
      <div style={{
        background: 'white',
        padding: '2rem',
        borderRadius: '10px',
        boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
        width: '100%',
        maxWidth: '450px'
      }}>
        <h1 style={{ textAlign: 'center', color: '#667eea', marginBottom: '0.5rem' }}>
          Sales ERP
        </h1>
        <p style={{ textAlign: 'center', color: '#666', marginBottom: '2rem' }}>
          Login to your account
        </p>

        {error && (
          <div style={{
            background: '#fee',
            border: '1px solid #fcc',
            color: '#c33',
            padding: '0.75rem',
            borderRadius: '5px',
            marginBottom: '1rem'
          }}>
            {error}
          </div>
        )}

        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: '1rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '500' }}>
              Email
            </label>
            <input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
              disabled={loading}
              style={{
                width: '100%',
                padding: '0.75rem',
                border: '1px solid #ddd',
                borderRadius: '5px',
                fontSize: '1rem'
              }}
            />
          </div>

          <div style={{ marginBottom: '1.5rem' }}>
            <label style={{ display: 'block', marginBottom: '0.5rem', fontWeight: '500' }}>
              Password
            </label>
            <input
              type="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              disabled={loading}
              style={{
                width: '100%',
                padding: '0.75rem',
                border: '1px solid #ddd',
                borderRadius: '5px',
                fontSize: '1rem'
              }}
            />
          </div>

          <button
            type="submit"
            disabled={loading}
            style={{
              width: '100%',
              padding: '0.75rem',
              background: loading ? '#aaa' : '#667eea',
              color: 'white',
              border: 'none',
              borderRadius: '5px',
              fontSize: '1rem',
              fontWeight: '600',
              cursor: loading ? 'not-allowed' : 'pointer'
            }}
          >
            {loading ? 'Logging in...' : 'Login'}
          </button>
        </form>

        <div style={{ marginTop: '2rem', padding: '1rem', background: '#f5f5f5', borderRadius: '5px' }}>
          <p style={{ margin: '0 0 0.75rem 0', fontWeight: '600', fontSize: '0.9rem', color: '#333' }}>
            🇮🇳 Demo Accounts:
          </p>
          <div style={{ fontSize: '0.85rem', lineHeight: '1.6' }}>
            <p style={{ margin: '0.25rem 0' }}>
              <strong>Admin 1:</strong> admin@biziverse.com / Admin@123
            </p>
            <p style={{ margin: '0.25rem 0' }}>
              <strong>Admin 2:</strong> admin@cloudsuite.com / Admin@123
            </p>
            <p style={{ margin: '0.25rem 0' }}>
              <strong>Partner:</strong> mike@partners.com / Admin@123
            </p>
            <p style={{ margin: '0.25rem 0' }}>
              <strong>Test Partner:</strong> partner@test.com / Partner@123
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Login;
